import { notify } from '../helpers/notification.helpers';

interface NotificationHook {
  triggerNotification: (props: Parameters<typeof notify>[1]) => void;
}

const useNotification = (): NotificationHook => {
  const notificationElem = useContext(NotificationContext);

  const triggerNotification = async (props: Parameters<typeof notify>[1]) => {
    if (!notificationElem) return;

    try {
      await notify(notificationElem, props);
    } catch (error) {
      console.error(error);
    }
  };

  return { triggerNotification };
};

export default useNotification;
